    $hashTerm(hasher, _nodeKindsStruct.blankNodeOrLiteralNodeKindProperty);
    $hashTerm(hasher, _nodeKindsStruct.iriNodeKindProperty);
    $hashTerm(hasher, _nodeKindsStruct.iriOrLiteralNodeKindProperty);
    $hashTerm(hasher, _nodeKindsStruct.literalNodeKindProperty);
    return hasher;
