  export function hash<HasherT extends $Hasher>(
    hasher: HasherT,
    _propertyNamesStruct: PropertyNamesStruct,
  ): HasherT {
    PropertyNamesStruct.hashShaclProperties(hasher, _propertyNamesStruct);
    hasher.update(_propertyNamesStruct.$identifier().value);
    hasher.update(_propertyNamesStruct.$type);
    return hasher;
  }

  export function hashShaclProperties<HasherT extends $Hasher>(
    hasher: HasherT,
    _propertyNamesStruct: PropertyNamesStruct,
  ): HasherT {
    $hashString(hasher, _propertyNamesStruct.actualPropertyName1);
    $hashString(hasher, _propertyNamesStruct.actualPropertyName2);
    $hashString(hasher, _propertyNamesStruct.actualPropertyName3);
    $hashString(hasher, _propertyNamesStruct.actualPropertyName4);
    $hashString(hasher, _propertyNamesStruct.actualPropertyName5);
    return hasher;
  }

  export type Identifier = BlankNode | NamedNode;

